       install_panic_hook();
       let args = Args::parse();
       // ... file open + player load from 2.1.1 ...

       let mut terminal = setup_terminal().unwrap_or_else(|e| {
           eprintln!("Failed to initialize terminal: {e}");
           std::process::exit(1);
       });

       // Run the app (placeholder for now — just clear screen and wait for 'q')
       let result = run(&mut terminal, player, &args);

       // Always restore terminal, even if run() returned an error
       let _ = restore_terminal(&mut terminal);

