   ```

2. Implement the event loop as `App::run()`:

   ```rust
   use crossterm::event::{self, Event, KeyCode, KeyEvent, KeyModifiers};
   use ratatui::Terminal;
   use ratatui::backend::CrosstermBackend;

   type Tui = Terminal<CrosstermBackend<std::io::Stdout>>;

   impl App {
       pub fn run(&mut self, terminal: &mut Tui) -> std::io::Result<()> {
           let mut last_tick = Instant::now();

           loop {
               // Render
               terminal.draw(|frame| self.render(frame))?;

               // Compute timeout
               let timeout = self.player.time_to_next_event()
                   .unwrap_or(std::time::Duration::from_millis(100));

               // Poll for input
               if event::poll(timeout)? {
                   if let Event::Key(key) = event::read()? {
                       self.handle_key(key);
                   }
                   // Also handle Event::Resize — trigger re-render (happens automatically since we loop)
               }

               // Advance playback
               let now = Instant::now();
               let dt = now.duration_since(last_tick).as_secs_f64();
               last_tick = now;

               if self.player.is_playing() {
                   self.player.tick(dt);
               }

               if self.should_quit {
                   break;
               }
           }
           Ok(())
       }
   }
   ```

3. Implement basic key handling (Phase 2 subset only):

   ```rust
   impl App {
       fn handle_key(&mut self, key: KeyEvent) {
           // Ignore key release events (crossterm 0.27+ sends both press and release)
           if key.kind != event::KeyEventKind::Press {
               return;
           }

           self.last_interaction = Instant::now();

           match key.code {
               KeyCode::Char('q') | KeyCode::Esc => {
                   self.should_quit = true;
               }
               KeyCode::Char(' ') => {
                   self.player.toggle();
               }
               KeyCode::Right => {
                   self.player.seek_relative(5.0);
                   self.show_controls = true;
               }
               KeyCode::Left => {
                   self.player.seek_relative(-5.0);
                   self.show_controls = true;
               }
               _ => {}
           }
       }
   }
   ```

4. Implement placeholder rendering (real rendering comes from Epic 2.2's TerminalView widget):

   ```rust
   use ratatui::Frame;
   use ratatui::widgets::{Block, Borders, Paragraph};

   impl App {
       fn render(&self, frame: &mut Frame) {
           let area = frame.area();

           // Placeholder: show recording info text until TerminalView widget is ready
           let info = format!(
               "speedrun — {}x{} | {:.1}s / {:.1}s | {} | {:.1}x",
               self.player.size().0,
               self.player.size().1,
               self.player.current_time(),
               self.player.duration(),
               if self.player.is_playing() { "playing" } else { "paused" },
               self.player.speed(),
           );

           let paragraph = Paragraph::new(info)
               .block(Block::default().borders(Borders::ALL).title("speedrun"));
           frame.render_widget(paragraph, area);
       }
   }
   ```

5. Update `main.rs` to use App:
   - Replace the placeholder `run()` function with:
     ```rust
     let mut app = app::App::new(player, !args.no_controls);
     let result = app.run(&mut terminal);
     ```
   - Remove the old placeholder `run()` function.

6. Make `mod app;` public in `main.rs` (it was a placeholder from 2.1.1).

## Acceptance criteria

- [ ] `speedrun <file.cast>` launches, shows placeholder info, and plays (time advances)
- [ ] `Space` toggles play/pause — placeholder display updates to show "playing" / "paused"
- [ ] `→` seeks forward 5s — current time updates
- [ ] `←` seeks backward 5s — current time updates
- [ ] `q` or `Esc` quits cleanly
- [ ] Terminal resize doesn't crash (re-render adapts to new size)
- [ ] Event loop uses `time_to_next_event()` for efficient polling (no busy-waiting)
- [ ] At end of recording, playback auto-pauses (no crash, no spinning)
- [ ] `--start-at` correctly seeks before playback starts
- [ ] `--no-controls` sets `show_controls = false` on App
- [ ] `cargo build -p speedrun` compiles cleanly
- [ ] `cargo clippy --workspace -- -D warnings` passes
- [ ] `cargo fmt --check` passes

NOTES:

### Codebase context

**Depends on 2.1.2**: Terminal lifecycle (`setup_terminal`, `restore_terminal`, panic hook) already exists. This ticket replaces the placeholder `run()` with the real App-based event loop.

**Player API used in the event loop:**
- `player.time_to_next_event() -> Option<Duration>` — returns `None` when paused or at end
- `player.tick(dt: f64) -> bool` — advance by wall-clock seconds, returns true if state changed
- `player.is_playing() -> bool`
- `player.toggle()` — play/pause toggle
- `player.seek_relative(delta: f64)` — relative seek
- `player.current_time() -> f64`, `player.duration() -> f64`, `player.speed() -> f64`, `player.size() -> (u16, u16)`

**crossterm key event handling**: crossterm 0.27+ sends `KeyEventKind::Press`, `KeyEventKind::Release`, and `KeyEventKind::Repeat`. Filter to only handle `Press` events to avoid double-processing.

**Rendering is intentionally placeholder**: The `render()` method shows text info about the player state. It will be replaced with the real TerminalView widget from Epic 2.2. The event loop structure itself is final — only the rendering call changes.

**`last_interaction` tracking**: Stored for future use by the controls auto-hide logic (Phase 3). Not actively used in this ticket beyond being set on each keypress.

