let player = load_test_file("minimal_v2.cast");
player.seek(player.duration());
assert!(player.screen()[0].text().starts_with("expected text"));
```

## Timing precision

Use an epsilon for floating-point time comparisons:
```rust
const EPSILON: f64 = 1e-10;
fn assert_time_eq(actual: f64, expected: f64) {
    assert!((actual - expected).abs() < EPSILON, "got {actual}, expected {expected}");
}
```

